var raw = $input.first().json;
var body = raw.body || raw;
var data = body.data || body;
var tenantId = String(body.tenantId || data.tenantId || '');

function esc(v) {
  return v == null ? '' : String(v).replace(/'/g, "''");
}

const uuidRegex = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
if (!uuidRegex.test(tenantId)) {
  throw new Error('Invalid tenantId');
}

var tid = esc(tenantId);

// Optimisation : CTEs au lieu de 16 sous-requêtes — chaque table lue 1 seule fois
var query = "WITH " +
  // 1 seul scan de equipe_members
  "em AS (SELECT " +
    "COUNT(*) FILTER (WHERE actif = true) as total, " +
    "COUNT(*) FILTER (WHERE actif = true AND contrat_type = 'CDI') as cdi, " +
    "COUNT(*) FILTER (WHERE actif = true AND contrat_type = 'CDD') as cdd " +
    "FROM equipe_members WHERE tenant_id = '" + tid + "'), " +
  // 1 seul scan de rh_contrats
  "rc AS (SELECT " +
    "COUNT(*) FILTER (WHERE statut = 'actif') as actifs, " +
    "COUNT(*) FILTER (WHERE statut = 'actif' AND date_fin IS NOT NULL AND date_fin BETWEEN NOW() AND NOW() + INTERVAL '30 days') as expirant_30j, " +
    "COALESCE(SUM(salaire_base) FILTER (WHERE statut = 'actif'), 0) as masse_salariale " +
    "FROM rh_contrats WHERE tenant_id = '" + tid + "'), " +
  // 1 seul scan de rh_conges
  "rco AS (SELECT " +
    "COUNT(*) FILTER (WHERE statut = 'en_attente') as en_attente, " +
    "COUNT(*) FILTER (WHERE statut = 'approuve' AND date_debut <= NOW() AND date_fin >= NOW()) as en_cours " +
    "FROM rh_conges WHERE tenant_id = '" + tid + "'), " +
  // 1 seul scan de rh_formations
  "rf AS (SELECT " +
    "COUNT(*) FILTER (WHERE statut = 'en_cours') as en_cours, " +
    "COUNT(*) FILTER (WHERE statut = 'planifiee') as planifiees " +
    "FROM rh_formations WHERE tenant_id = '" + tid + "'), " +
  // inscriptions formations
  "rif AS (SELECT COUNT(*) as total FROM rh_inscriptions_formations WHERE tenant_id = '" + tid + "'), " +
  // 1 seul scan de rh_evaluations
  "rev AS (SELECT " +
    "COUNT(*) FILTER (WHERE DATE_TRUNC('month', created_at) = DATE_TRUNC('month', NOW())) as ce_mois, " +
    "COALESCE(AVG(note_globale) FILTER (WHERE annee = EXTRACT(YEAR FROM NOW())), 0) as note_moyenne " +
    "FROM rh_evaluations WHERE tenant_id = '" + tid + "'), " +
  // entretiens
  "re AS (SELECT COUNT(*) as planifies FROM rh_entretiens WHERE tenant_id = '" + tid + "' AND statut = 'planifie' AND date_entretien >= NOW()), " +
  // documents
  "rd AS (SELECT COUNT(*) as total FROM rh_documents WHERE tenant_id = '" + tid + "'), " +
  // bulletins
  "rb AS (SELECT COUNT(*) as mois_courant FROM rh_bulletins_paie WHERE tenant_id = '" + tid + "' AND mois = EXTRACT(MONTH FROM NOW()) AND annee = EXTRACT(YEAR FROM NOW())) " +
  // SELECT final — 1 seule row
  "SELECT " +
    "em.total as effectif_total, em.cdi as effectif_cdi, em.cdd as effectif_cdd, " +
    "rc.actifs as contrats_actifs, rc.expirant_30j as contrats_expirant_30j, rc.masse_salariale, " +
    "rco.en_attente as conges_en_attente, rco.en_cours as conges_en_cours, " +
    "rf.en_cours as formations_en_cours, rf.planifiees as formations_planifiees, rif.total as total_inscriptions_formations, " +
    "rev.ce_mois as evaluations_ce_mois, rev.note_moyenne as note_moyenne_annee, " +
    "re.planifies as entretiens_planifies, " +
    "rd.total as total_documents, " +
    "rb.mois_courant as bulletins_mois_courant, " +
    "COALESCE(rco.en_cours * 100.0 / NULLIF(em.total, 0), 0) as taux_absenteisme " +
  "FROM em, rc, rco, rf, rif, rev, re, rd, rb";

return [{json: {query: query}}];

var r = $input.first().json;
var result = {
  effectif: {
    total: Number(r.effectif_total || 0),
    cdi: Number(r.effectif_cdi || 0),
    cdd: Number(r.effectif_cdd || 0)
  },
  contrats: {
    actifs: Number(r.contrats_actifs || 0),
    expirant30j: Number(r.contrats_expirant_30j || 0)
  },
  conges: {
    enAttente: Number(r.conges_en_attente || 0),
    enCours: Number(r.conges_en_cours || 0)
  },
  formations: {
    enCours: Number(r.formations_en_cours || 0),
    planifiees: Number(r.formations_planifiees || 0),
    totalInscriptions: Number(r.total_inscriptions_formations || 0)
  },
  evaluations: {
    ceMois: Number(r.evaluations_ce_mois || 0),
    noteMoyenneAnnee: Math.round(Number(r.note_moyenne_annee || 0) * 100) / 100
  },
  entretiens: {
    planifies: Number(r.entretiens_planifies || 0)
  },
  documents: {
    total: Number(r.total_documents || 0)
  },
  paie: {
    bulletinsMoisCourant: Number(r.bulletins_mois_courant || 0),
    masseSalariale: Number(r.masse_salariale || 0)
  },
  tauxAbsenteisme: Math.round(Number(r.taux_absenteisme || 0) * 100) / 100
};
return [{json: {success: true, data: result}}];
